import React from "react";
import "./InternshipCard.css";

export default function InternshipCard({ internship, onApply, onEdit, onDelete, userRole, applicationStatus }) {
  return (
    <div className="internship-card">
      <h3>{internship.title}</h3>
      <p><strong>Company:</strong> {internship.company}</p>
      <p><strong>Category:</strong> {internship.category}</p>
      <p><strong>Location:</strong> {internship.location}</p>
      <p><strong>Mode:</strong> {internship.mode}</p>
      <p><strong>Duration:</strong> {internship.duration}</p>
      <p><strong>Stipend:</strong> ₹{internship.stipend}</p>

      {userRole === "student" && (
        <p><strong>Status:</strong> {applicationStatus || "Not Applied"}</p>
      )}

      {userRole === "student" && (
        <button onClick={() => onApply(internship._id)} disabled={!!applicationStatus}>
          {applicationStatus ? "Applied" : "Apply"}
        </button>
      )}

      {(userRole === "admin" || userRole === "hr") && (
        <div className="admin-actions">
          <button onClick={() => onEdit(internship)}>Edit</button>
          <button onClick={() => onDelete(internship._id)}>Delete</button>
        </div>
      )}
    </div>
  );
}
